// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance for a simple type (e.g., int)
    hexi::block_allocator<int, element_count> allocator;

    // Demonstrate initial state: free list is pre-populated with element_count blocks
    // (This happens in the constructor via initialise_free_list())

    // Allocate all blocks from the free list
    int* blocks[element_count];
    for (size_t i = 0; i < element_count; ++i) {
        blocks[i] = allocator.allocate(i); // Each allocation uses pop() internally
    }

    // At this point, the free list should be empty

    // Deallocate one block, which should push it back to the free list
    allocator.deallocate(blocks[0]); // This calls push() internally

    // Now allocate again - this should reuse the previously deallocated block
    int* reused_block = allocator.allocate(99); // Uses pop() to get the pushed block

    // Verify the value in the reused block
    // Note: The value 99 should be in *reused_block

    // Deallocate all remaining blocks to clean up
    for (size_t i = 1; i < element_count; ++i) {
        allocator.deallocate(blocks[i]);
    }

    // The destructor will automatically call deallocate() on any remaining allocated blocks
}
