```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Create destination buffer
    std::vector<uint8_t> destination(bytes_to_preview);

    // Use the copy function to preview data without advancing read pointer
    storage.copy(destination.data(), bytes_to_preview);

    return destination;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    // Calculate readable size (write_offset - read_offset)
    size_t readable_size = storage.write_offset - storage.read_offset;

    // Calculate free space (block_size - write_offset)
    size_t free_space = block_size - storage.write_offset;

    return BufferStatus<>{readable_size, free_space};
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Reset both read and write offsets to 0
    storage.read_offset = 0;
    storage.write_offset = 0;
}
```

## Key Implementation Points:

1. **preview_data_without_consuming**: 
   - Uses the `copy` member function which internally handles the memory copy without advancing the read pointer
   - Creates a vector as the destination buffer
   - Returns the previewed data as a vector of uint8_t

2. **check_buffer_status**:
   - Directly accesses `read_offset` and `write_offset` members
   - Calculates readable size as the difference between write and read offsets
   - Calculates free space as the remaining capacity in the buffer
   - Returns a `BufferStatus` struct with the calculated values

3. **reset_buffer**:
   - Directly modifies both `read_offset` and `write_offset` to 0
   - This effectively resets the buffer to its initial state

